WITH right_fg0 AS (SELECT * FROM (SELECT "hopsworks_tl_payload_0" AS "pk", "hopsworks_tl_payload_1" AS "ts", "hopsworks_tl_payload_2" AS "is_fraud", "hopsworks_tl_payload_3" AS "join_pk_pk", "hopsworks_tl_payload_4" AS "join_evt_ts", "hopsworks_tl_out_0" AS "amount_sum", "hopsworks_tl_out_1" AS "count" FROM (SELECT "hopsworks_tl_marker", "hopsworks_tl_payload_0", "hopsworks_tl_payload_1", "hopsworks_tl_payload_2", "hopsworks_tl_payload_3", "hopsworks_tl_payload_4", SUM("hopsworks_tl_src_0") OVER (PARTITION BY "hopsworks_tl_e_0" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN 3600000000 PRECEDING AND CURRENT ROW) AS "hopsworks_tl_out_0", COUNT("hopsworks_tl_src_evt") OVER (PARTITION BY "hopsworks_tl_e_0" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN 3600000000 PRECEDING AND CURRENT ROW) AS "hopsworks_tl_out_1" FROM (SELECT "fg1"."pk" AS "hopsworks_tl_e_0", EPOCH_US("fg1"."ts") AS "hopsworks_tl_ord", 0 AS "hopsworks_tl_marker", "fg1"."ts" AS "hopsworks_tl_src_evt", "fg1"."amount" AS "hopsworks_tl_src_0", NULL AS "hopsworks_tl_payload_0", NULL AS "hopsworks_tl_payload_1", NULL AS "hopsworks_tl_payload_2", NULL AS "hopsworks_tl_payload_3", NULL AS "hopsworks_tl_payload_4" FROM "fs1"."fg1_1" AS "fg1" WHERE "fg1"."pk" IN (SELECT "fg0"."pk" FROM "fs1"."labels_1" AS "fg0") AND EPOCH_US("fg1"."ts") >= (SELECT MIN(EPOCH_US("fg0"."ts")) FROM "fs1"."labels_1" AS "fg0") - 3600000000 AND EPOCH_US("fg1"."ts") <= (SELECT MAX(EPOCH_US("fg0"."ts")) FROM "fs1"."labels_1" AS "fg0") UNION ALL SELECT "fg0"."pk" AS "hopsworks_tl_e_0", EPOCH_US("fg0"."ts") AS "hopsworks_tl_ord", 1 AS "hopsworks_tl_marker", NULL AS "hopsworks_tl_src_evt", NULL AS "hopsworks_tl_src_0", "fg0"."pk" AS "hopsworks_tl_payload_0", "fg0"."ts" AS "hopsworks_tl_payload_1", "fg0"."is_fraud" AS "hopsworks_tl_payload_2", "fg0"."pk" AS "hopsworks_tl_payload_3", "fg0"."ts" AS "hopsworks_tl_payload_4" FROM "fs1"."labels_1" AS "fg0") AS hopsworks_tl) AS hopsworks_tl_win WHERE "hopsworks_tl_marker" = 1) AS NA) (SELECT "right_fg0"."pk"